129	text_import_2026-03-10 08.30.03.txt	mixed	1	156	40	{"segments": [{"end": 1.0, "start": 0.0, "speaker": "client", "anchor_mode": "greeting", "corrections": [], "refined_text": "Hello, I'm speaking. [MONTH] [VALUE], [VALUE].", "original_text": "Hello, I'm speaking. [MONTH] [VALUE], [VALUE].", "low_confidence_words": []}, {"end": 2.0, "start": 1.0, "speaker": "agent", "anchor_mode": "greeting", "corrections": [{"source": "ngram_anchor", "original": "morning po ma'am", "corrected": "morning po maam", "confidence_delta": 1.0}], "refined_text": "Hello. Hello po. Good morning. Looking kay Ma'am [PERSON]. Yes po. Good morning po maam. this is [PERSON] from SP [ORGANIZATION] Firm po. Before tayo ma'am mag-proceed, kindly dictate po ma'am ng birthday for verification po.", "original_text": "Hello. Hello po. Good morning. Looking kay Ma'am [PERSON]. Yes po. Good morning po ma'am. this is [PERSON] from SP [ORGANIZATION] Firm po. Before tayo ma'am mag-proceed, kindly dictate po ma'am ng birthday for verification po.", "low_confidence_words": []}, {"end": 3.0, "start": 2.0, "speaker": "agent", "anchor_mode": "general", "corrections": [], "refined_text": "Okay, thank you ma'am for confirmation. Yung line po natin ma'am will be recorded.", "original_text": "Okay, thank you ma'am for confirmation. Yung line po natin ma'am will be recorded.", "low_confidence_words": []}, {"end": 4.0, "start": 3.0, "speaker": "agent", "anchor_mode": "negotiation", "corrections": [], "refined_text": "Regarding po ito ma'am, sa inyong unsettled account ma'am sa credit card po.", "original_text": "Regarding po ito ma'am, sa inyong unsettled account ma'am sa credit card po.", "low_confidence_words": []}, {"end": 5.0, "start": 4.0, "speaker": "client", "anchor_mode": "general", "corrections": [], "refined_text": "Oo, oo, oo.", "original_text": "Oo, oo, oo.", "low_confidence_words": []}, {"end": 6.0, "start": 5.0, "speaker": "agent", "anchor_mode": "general", "corrections": [], "refined_text": "Upon checking po kasi ma'am, yung balance po sa ngayon is [VALUE] pesos and [VALUE] centavos.", "original_text": "Upon checking po kasi ma'am, yung balance po sa ngayon is [VALUE] pesos and [VALUE] centavos.", "low_confidence_words": []}, {"end": 7.0, "start": 6.0, "speaker": "client", "anchor_mode": "general", "corrections": [{"source": "lexicon", "original": "nasyadong", "corrected": "masyadong", "confidence_delta": null}], "refined_text": "Yung kettle yan, masyadong malaki. Hindi ko siya kaya eh.", "original_text": "Yung kettle yan, nasyadong malaki. Hindi ko siya kaya eh.", "low_confidence_words": []}, {"end": 8.0, "start": 7.0, "speaker": "agent", "anchor_mode": "negotiation", "corrections": [{"source": "lexicon", "original": "ma-i-settled", "corrected": "ma-settle", "confidence_delta": null}, {"source": "ngram_anchor", "original": "ma'am ginamit itong", "corrected": "ma'am ginamit inyong", "confidence_delta": 1.0}], "refined_text": "May no'am tama po today, ma-settle na po yung balance ni ma'am. Okay, ano po? Saan po pa ma'am ginamit inyong credit card?", "original_text": "May no'am tama po today, ma-i-settled na po yung balance ni ma'am. Okay, ano po? Saan po pa ma'am ginamit itong credit card?", "low_confidence_words": []}, {"end": 9.0, "start": 8.0, "speaker": "agent", "anchor_mode": "general", "corrections": [], "refined_text": "Okay, itong account niyo po kasi", "original_text": "Okay, itong account niyo po kasi", "low_confidence_words": []}, {"end": 10.0, "start": 9.0, "speaker": "client", "anchor_mode": "general", "corrections": [{"source": "lexicon", "original": "na-scam", "corrected": "na-scam", "confidence_delta": null}], "refined_text": "So yan, na-scam kami. Scam kami. Na-report ko yan kay [BANK NAME].", "original_text": "So yan, na-scam kami. Scam kami. Na-report ko yan kay [BANK NAME].", "low_confidence_words": []}, {"end": 11.0, "start": 10.0, "speaker": "agent", "anchor_mode": "general", "corrections": [], "refined_text": "Okay, pero ma'am", "original_