130	text_import_2026-03-10 08.44.19.txt	mixed	1	98	90	{"segments": [{"end": 1.0, "start": 0.0, "speaker": "agent", "anchor_mode": "greeting", "corrections": [{"source": "gemini", "original": "Kasapad", "corrected": "SP Madrid", "confidence_delta": null}], "refined_text": "Hello. Good afternoon po ni SP Madrid.", "original_text": "Hello. Good afternoon po ni Kasapad.", "low_confidence_words": []}, {"end": 2.0, "start": 1.0, "speaker": "client", "anchor_mode": "ptp_commitment", "corrections": [], "refined_text": "Yes. Sige, ngayon.", "original_text": "Yes. Sige, ngayon.", "low_confidence_words": []}, {"end": 3.0, "start": 2.0, "speaker": "agent", "anchor_mode": "introduction", "corrections": [{"source": "ngram_anchor", "original": "this is janre", "corrected": "this is jared", "confidence_delta": 1.0}, {"source": "gemini", "original": "jared Kake", "corrected": "Jared [PERSON]", "confidence_delta": null}, {"source": "gemini", "original": "SC [ORGANIZATION] Firm", "corrected": "SP Madrid Law Firm", "confidence_delta": null}], "refined_text": "Good afternoon po, sir. By the way, sir, this is Jared [PERSON] po from SP Madrid Law Firm.", "original_text": "Good afternoon po, sir. By the way, sir, this is Janre Kake po from SC [ORGANIZATION] Firm.", "low_confidence_words": []}, {"end": 4.0, "start": 3.0, "speaker": "agent", "anchor_mode": "greeting", "corrections": [], "refined_text": "This call, sir, is regarding on your personal banking matters with [BANK NAME]. Hello.", "original_text": "This call, sir, is regarding on your personal banking matters with [BANK NAME]. Hello.", "low_confidence_words": []}, {"end": 5.0, "start": 4.0, "speaker": "client", "anchor_mode": "general", "corrections": [{"source": "gemini", "original": "angayon", "corrected": "ngayon", "confidence_delta": null}], "refined_text": "[BANK NAME] ba ito? Oo, ngayon.", "original_text": "[BANK NAME] ba ito? Oo, angayon.", "low_confidence_words": []}, {"end": 6.0, "start": 5.0, "speaker": "agent", "anchor_mode": "general", "corrections": [], "refined_text": "Yes, sir. External legal counsel po ni [BANK NAME]. Bali, your account was fully endorsed to the Office of Attorney [ORGANIZATION] for final assessment, sir.", "original_text": "Yes, sir. External legal counsel po ni [BANK NAME]. Bali, your account was fully endorsed to the Office of Attorney [ORGANIZATION] for final assessment, sir.", "low_confidence_words": []}, {"end": 7.0, "start": 6.0, "speaker": "agent", "anchor_mode": "general", "corrections": [], "refined_text": "So, before lang tayo, sir, mag-proceed to discuss any information, just for security purposes and verification", "original_text": "So, before lang tayo, sir, mag-proceed to discuss any information, just for security purposes and verification", "low_confidence_words": []}, {"end": 8.0, "start": 7.0, "speaker": "agent", "anchor_mode": "contact_info", "corrections": [{"source": "gemini", "original": "data board", "corrected": "date of birth", "confidence_delta": null}], "refined_text": "para dictate na po ako ng inyong date of birth.", "original_text": "para dictate na po ako ng inyong data board.", "low_confidence_words": []}, {"end": 9.0, "start": 8.0, "speaker": "client", "anchor_mode": "general", "corrections": [], "refined_text": "[MONTH] [VALUE]rd, [VALUE]rd, [VALUE]rd. Kasi nakakuha ko ng demand letter.", "original_text": "[MONTH] [VALUE]rd, [VALUE]rd, [VALUE]rd. Kasi nakakuha ko ng demand letter.", "low_confidence_words": []}, {"end": 10.0, "start": 9.0, "speaker": "agent", "anchor_mode": "consent_to_record", "corrections": [{"source": "ngram_anchor", "original": "recorded line tayo", "corrected": "recorded line and", "confidence_delta": 1.0}, {"source": "gemini", "original": "over the recorded line and. So,", "corrected": "recorded line tayo. So,"}], "refined_text": "Okay, thank you for the verification, sir, recorded line tayo. So, sir, napatawag na naman po ako regarding dito sa inyong [BANK NAME] credit card.", "original_text": "Okay, thank you for the verification, sir, over the recorded line tayo. So, sir, napatawag na naman po ako regarding dito sa inyong [BANK NAME] credit card.", "low_confidence_words": []}, {"end": 11.0, "start": 10.0, "speaker": "agent", "anchor_mode": "general", "corrections": [{"source": "ngram_anchor", "original": "the bank is", "corrected": "the bank and", "confidence_delta": 1.0}, {"source": "gemini", "original": "malinwag", "corrected": "malinaw", "confidence_delta": null}], "refined_text": "the bank and now asking, sir, ano po yung malinaw ninyong plan na dito, sir?", "original_text": "The bank is now asking, sir, ano po yung malinwag ninyong plan na dito, sir?", "low_confidence_words": []}, {"end": 12.0, "start": 11.0, "speaker": "client", "anchor_mode": "general", "corrections": [], "refined_text": "May pumunta ditong person or agent na collector. And letter sa akin, nang buo ito sa letter, yung amount.", "original_text": "May pumunta ditong person or agent na collector. And letter sa akin, nang buo ito sa letter, yung amount.", "low_confidence_words": []}, {"end": 13.0, "start": 12.0, "speaker": "client", "anchor_mode": "general", "corrections": [], "refined_text": "So, unfortunately, nag-email ako dun sa nakalagay na contact, email. and nag-propose ako ng amount na kaya ko.", "original_text": "So, unfortunately, nag-email ako dun sa nakalagay na contact, email. and nag-propose ako ng amount na kaya ko.", "low_confidence_words": []}, {"end": 14.0, "start": 13.0, "speaker": "client", "anchor_mode": "objection_handling", "corrections": [{"source": "gemini", "original": "minat na itumat", "corrected": "amount na itinatama", "confidence_delta": null}, {"source": "gemini", "original": "pagaya", "corrected": "pag-apply", "confidence_delta": null}], "refined_text": "Kasi actually, yung buong yun, hindi ko kaya. Tsaka yung amount na itinatama na sa akin na isa sa pag-apply mo", "original_text": "Kasi actually, yung buong yun, hindi ko kaya. Tsaka yung minat na itumat na sa 